@strawberry.type
class Product:
    id: strawberry.ID
    sku: Optional[str]
    name: str
    description: Optional[str]
    price: float
    currency: str
    is_active: bool
    created_at: dt.datetime

    @strawberry.field
    def seller(self, info: Info) -> Optional[Seller]:
        m: ProductModel = info.context["product_model"]
        if m.seller is None:
            return None
        s = m.seller
        return Seller(id=str(s.id), name=s.name, rating=s.rating, created_at=s.created_at)

    @strawberry.field
    def categories(self, info: Info) -> List[Category]:
        m: ProductModel = info.context["product_model"]
        return [Category(id=str(c.id), name=c.name, created_at=c.created_at) for c in (m.categories or [])]

    @strawberry.field
    def images(self, info: Info) -> List[Image]:
        m: ProductModel = info.context["product_model"]
        imgs = sorted((m.images or []), key=lambda x: (x.sort_order, x.id))
        return [
            Image(id=str(i.id), url=i.url, alt_text=i.alt_text, sort_order=i.sort_order, created_at=i.created_at)
            for i in imgs
        ]

    @strawberry.field
    def reviews(self, info: Info) -> List[Review]:
        m: ProductModel = info.context["product_model"]
        revs = sorted((m.reviews or []), key=lambda x: (x.created_at, x.id))
        return [
            Review(
                id=str(r.id),
                author=r.author,
                rating=r.rating,
                title=r.title,
                body=r.body,
                created_at=r.created_at,
            )
            for r in revs
        ]


def _product_to_gql(m: ProductModel) -> Product:
    return Product(
        id=str(m.id),
        sku=m.sku,
        name=m.name,
        description=m.description,
        price=m.price,
        currency=m.currency,
        is_active=m.is_active,
        created_at=m.created_at,
    )


def _with_product_context(info: Info, product_model: ProductModel) -> Dict[str, Any]:
    ctx = dict(info.context)
    ctx["product_model"] = product_model
    return ctx


@strawberry.type
class Query:
    @strawberry.field
    def product(self, info: Info, id: strawberry.ID) -> Optional[Product]:
        db: Session = info.context["db"]
        m = (
            db.query(ProductModel)
            .options(
                selectinload(ProductModel.categories),
                selectinload(ProductModel.images),
                selectinload(ProductModel.reviews),
                selectinload(ProductModel.seller),
            )
            .filter(ProductModel.id == int(str(id)))
            .first()
        )
        if not m:
            return None
        p = _product_to_gql(m)
        info.context.update(_with_product_context(info, m))
        return p

    @strawberry.field
    def products(
        self,
        info: Info,
        search: Optional[str] = None,
        category_id: Optional[strawberry.ID] = None,
        seller_id: Optional[strawberry.ID] = None,
        is_active: Optional[bool] = None,
        limit: Optional[int] = None,
        offset: Optional[int] = None,
    ) -> List[Product]:
        db: Session = info.context["db"]
        q = db.query(ProductModel).options(
            selectinload(ProductModel.categories),
            selectinload(ProductModel.images),
            selectinload(ProductModel.reviews),
            selectinload(ProductModel.seller),
        )

        if search:
            like = f"%{search}%"
            q = q.filter((ProductModel.name.ilike(like)) | (ProductModel.description.ilike(like)) | (ProductModel.sku.ilike(like)))
        if category_id is not None:
            cid = int(str(category_id))
            q = q.join(product_category).filter(product_category.c.category_id == cid)
        if seller_id is not None:
            q = q.filter(ProductModel.seller_id == int(str(seller_id)))
        if is_active is not None:
            q = q.filter(ProductModel.is_active == is_active)

        q = q.order_by(ProductModel.id.asc())
        if offset:
            q = q.offset(offset)
        if limit:
            q = q.limit(limit)

        models = q.all()
        products = []
        for m in models:
            p = _product_to_gql(m)
            products.append(p)
        info.context["product_models_by_id"] = {m.id: m for m in models}
        return products

    @strawberry.field
    def seller(self, info: Info, id: strawberry.ID) -> Optional[Seller]:
        db: Session = info.context["db"]
        s = db.query(SellerModel).filter(SellerModel.id == int(str(id))).first()
        if not s:
            return None
        return Seller(id=str(s.id), name=s.name, rating=s.rating, created_at=s.created_at)

    @strawberry.field
    def sellers(self, info: Info) -> List[Seller]:
        db: Session = info.context["db"]
        ss = db.query(SellerModel).order_by(SellerModel.id.asc()).all()
        return [Seller(id=str(s.id), name=s.name, rating=s.rating, created_at=s.created_at) for s in ss]

    @strawberry.field
    def category(self, info: Info, id: strawberry.ID) -> Optional[Category]:
        db: Session = info.context["db"]
        c = db.query(CategoryModel).filter(CategoryModel.id == int(str(id))).first()
        if not c:
            return None
        return Category(id=str(c.id), name=c.name, created_at=c.created_at)

    @strawberry.field
    def categories(self, info: Info) -> List[Category]:
        db: Session = info.context["db"]
        cs = db.query(CategoryModel).order_by(CategoryModel.id.asc()).all()
        return [Category(id=str(c.id), name=c.name, created_at=c.created_at) for c in cs]


